 10Ôćĺconst TITLE_REFERENCE =
 11Ôćĺ  "recipe name, dish title, name of the food, nazwa przepisu, nazwa dania";
 12Ôćĺconst HEADER_REFERENCE =
 13Ôćĺ  "ingredients list, cooking directions, section heading, sk┼éadniki, przygotowanie, spos├│b wykonania";
 14Ôćĺconst NOISE_REFERENCE =
 15Ôćĺ  "page number, table of contents, book footer, garbled text";
 16Ôćĺ
 17Ôćĺ/**
 18Ôćĺ * Measurement units commonly found in ingredient lists
 19Ôćĺ */
 20Ôćĺconst MEASUREMENT_PATTERNS = [
 21Ôćĺ  "cup",
 22Ôćĺ  "cups",
 23Ôćĺ  "tbsp",
 24Ôćĺ  "tsp",
 25Ôćĺ  "tablespoon",
 26Ôćĺ  "teaspoon",
 27Ôćĺ  "oz",
 28Ôćĺ  "lb",
 29Ôćĺ  "gram",
 30Ôćĺ  "grams",
 31Ôćĺ  "kg",
 32Ôćĺ  "ml",
 33Ôćĺ  "liter",
 34Ôćĺ  "pinch",
 35Ôćĺ  "dash",
 36Ôćĺ  "handful",
 37Ôćĺ];
 38Ôćĺ
 39Ôćĺ/**
 40Ôćĺ * Patterns that identify recipe metadata lines (not titles)
 41Ôćĺ */
 42Ôćĺconst METADATA_PATTERNS = [
 43Ôćĺ  /^(SERVES?|MAKES?|YIELDS?)\b/i,
 44Ôćĺ  /^(PREP(ARATION)?|COOK(ING)?|PROOF|RISING|FERMENTATION|REST(ING)?)\s*(AND\s*)?(COOK(ING)?)?\s*TIME/i,
 45Ôćĺ  /^SAMPLE\s+SCHEDULE\b/i,
 46Ôćĺ  /^BULK\s+FERMENTATION\b/i,
 47Ôćĺ  /^(THIS\s+RECIPE\s+)?MAKES\b/i,
 48Ôćĺ];
 49Ôćĺ
 50Ôćĺ/**
 51Ôćĺ * Single-word non-title words ÔÇö standalone OCR fragments unlikely to be recipe titles
 52Ôćĺ */
 53Ôćĺconst NON_TITLE_WORDS = new Set([
 54Ôćĺ  "the", "and", "for", "but", "not", "you", "all", "can", "are", "was",
 55Ôćĺ  "has", "his", "her", "its", "our", "who", "how", "may", "new", "now",
 56Ôćĺ  "old", "see", "way", "did", "get", "let", "say", "she", "too", "use",
 57Ôćĺ  "buns", "with",
 58Ôćĺ]);
 59Ôćĺ
 60Ôćĺfunction looksLikeIngredient(line: string): boolean {
 61Ôćĺ  const lowerLine = line.toLowerCase();
 62Ôćĺ  return MEASUREMENT_PATTERNS.some((pattern) => lowerLine.includes(pattern));
 63Ôćĺ}
 64Ôćĺ
 65Ôćĺfunction startsWithNumber(line: string): boolean {
 66Ôćĺ  return /^\s*\d/.test(line);
 67Ôćĺ}
 68Ôćĺ
 69Ôćĺfunction isAllCaps(line: string): boolean {
 70Ôćĺ  const letters = line.replace(/[^a-zA-Z]/g, "");
 71Ôćĺ  return letters.length > 0 && letters === letters.toUpperCase();
 72Ôćĺ}
 73Ôćĺ
 74Ôćĺfunction looksLikeMetadata(text: string): boolean {
 75Ôćĺ  return METADATA_PATTERNS.some((pattern) => pattern.test(text.trim()));
 76Ôćĺ}
 77Ôćĺ
 78Ôćĺfunction isLikelyGarbled(text: string): boolean {
 79Ôćĺ  const letters = text.replace(/[^a-zA-Z]/g, "");
 80Ôćĺ  if (letters.length < 2) return true;
 81Ôćĺ
 82Ôćĺ  // Check vowel ratio ÔÇö English/Polish text typically has 30ÔÇô50% vowels
 83Ôćĺ  const vowels = letters.replace(/[^aeiouAEIOUyY─ů─Ö├│─ä─ś├ô]/g, "").length;
 84Ôćĺ  const vowelRatio = vowels / letters.length;
 85Ôćĺ  if (vowelRatio < 0.15 || vowelRatio > 0.85) return true;
 86Ôćĺ
 87Ôćĺ  // Single orphaned word ÔëĄ3 letters that isn't a common word
 88Ôćĺ  const words = text.trim().split(/\s+/);
 89Ôćĺ  const COMMON_SHORT = new Set([
 90Ôćĺ    "the", "and", "for", "but", "not", "you", "all", "can", "had", "her",
 91Ôćĺ    "was", "one", "our", "out", "are", "has", "his", "how", "its", "may",
 92Ôćĺ    "new", "now", "old", "see", "way", "who", "did", "get", "let", "say",
 93Ôćĺ    "she", "too", "use",
 94Ôćĺ  ]);
 95Ôćĺ  if (words.length === 1 && letters.length <= 3 && !COMMON_SHORT.has(text.trim().toLowerCase())) {
 96Ôćĺ    return true;
 97Ôćĺ  }
 98Ôćĺ
 99Ôćĺ  // Recipe titles never start with a lowercase letter
100Ôćĺ  if (/^[a-z]/.test(text.trim())) {
101Ôćĺ    return true;
102Ôćĺ  }
103Ôćĺ
104Ôćĺ  // Mid-text sentence boundary (". " followed by a letter) ÔÇö body text fragment spliced from multiple sentences
105Ôćĺ  const trimmed = text.trim();
106Ôćĺ  if (/\.\s+[a-zA-Z]/.test(trimmed) && !trimmed.endsWith(")")) {
107Ôćĺ    return true;
108Ôćĺ  }
109Ôćĺ
110Ôćĺ  // Multi-word candidate containing a garbled OCR fragment: a short lowercase word that isn't a known short word
111Ôćĺ  if (words.length >= 2) {
112Ôćĺ    const commonShort2 = new Set([
113Ôćĺ      "a", "i", "of", "or", "to", "in", "on", "is", "it", "an",
114Ôćĺ      "as", "at", "by", "do", "go", "if", "no", "so", "up", "we",
115Ôćĺ      "w", "z",  // Polish prepositions
116Ôćĺ    ]);
117Ôćĺ    const hasGarbledWord = words.some(
118Ôćĺ      (w) =>
119Ôćĺ        /^[a-z]/.test(w) &&
120Ôćĺ        w.replace(/[^a-z]/g, "").length <= 2 &&
121Ôćĺ        !commonShort2.has(w.toLowerCase())
122Ôćĺ    );
123Ôćĺ    if (hasGarbledWord) {
124Ôćĺ      return true;
125Ôćĺ    }
126Ôćĺ  }
127Ôćĺ
128Ôćĺ  return false;
129Ôćĺ}
130Ôćĺ
131Ôćĺfunction passesHardFilters(text: string): boolean {
132Ôćĺ  if (text.length < 3 || text.length > 80) return false;
133Ôćĺ  if (looksLikeIngredient(text)) return false;
134Ôćĺ  if (startsWithNumber(text)) return false;
135Ôćĺ  if (looksLikeMetadata(text)) return false;
136Ôćĺ  if (isLikelyGarbled(text)) return false;
137Ôćĺ  // Single-word non-title fragments
138Ôćĺ  const words = text.trim().split(/\s+/);
139Ôćĺ  if (words.length === 1 && NON_TITLE_WORDS.has(text.trim().toLowerCase())) return false;
140Ôćĺ  return true;
141Ôćĺ}
142Ôćĺ
143Ôćĺ/**
144Ôćĺ * Detect initial burst of short garbled lines.
145Ôćĺ * Returns the index of the first non-garbled or long line.
146Ôćĺ */
147Ôćĺfunction findBurstEnd(lines: Array<{ text: string }>): number {
148Ôćĺ  let i = 0;
149Ôćĺ  while (i < lines.length && lines[i].text.length < 20 && isLikelyGarbled(lines[i].text)) {
150Ôćĺ    i++;
151Ôćĺ  }
152Ôćĺ  return i;
153Ôćĺ}
154Ôćĺ
155Ôćĺfunction wordCount(text: string): number {
156Ôćĺ  return text.split(/\s+/).filter((w) => w.length > 0).length;
157Ôćĺ}
158Ôćĺ
159Ôćĺ/**
160Ôćĺ * Build candidate strings from lines: single lines plus multi-line joins (2-3 consecutive).
161Ôćĺ * Skips initial burst of short garbled lines. Scans all remaining lines. Caps at 25.
162Ôćĺ */
163Ôćĺfunction buildCandidates(
164Ôćĺ  lines: Array<string>
165Ôćĺ): Array<{ text: string; position: number }> {
166Ôćĺ  const nonEmptyLines: Array<{ text: string; index: number }> = [];
167Ôćĺ
168Ôćĺ  for (let i = 0; i < lines.length; i++) {
169Ôćĺ    const trimmed = lines[i].trim();
170Ôćĺ    if (trimmed.length > 0) {
171Ôćĺ      nonEmptyLines.push({ text: trimmed, index: i });
172Ôćĺ    }
173Ôćĺ  }
174Ôćĺ
175Ôćĺ  const burstEnd = findBurstEnd(nonEmptyLines);
176Ôćĺ  const candidates: Array<{ text: string; position: number }> = [];
177Ôćĺ  const seen = new Set<string>();
178Ôćĺ
179Ôćĺ  for (let i = burstEnd; i < nonEmptyLines.length; i++) {
180Ôćĺ    const line = nonEmptyLines[i];
181Ôćĺ
182Ôćĺ    // Single line
183Ôćĺ    if (passesHardFilters(line.text)) {
184Ôćĺ      const norm = line.text.toLowerCase();
185Ôćĺ      if (!seen.has(norm)) {
186Ôćĺ        seen.add(norm);
187Ôćĺ        candidates.push({ text: line.text, position: line.index });
188Ôćĺ      }
189Ôćĺ    }
190Ôćĺ
191Ôćĺ    // 2-line join
192Ôćĺ    if (i + 1 < nonEmptyLines.length) {
193Ôćĺ      const joined2 = `${line.text} ${nonEmptyLines[i + 1].text}`;
194Ôćĺ      if (passesHardFilters(joined2)) {
195Ôćĺ        const norm = joined2.toLowerCase();
196Ôćĺ        if (!seen.has(norm)) {
197Ôćĺ          seen.add(norm);
198Ôćĺ          candidates.push({ text: joined2, position: line.index });
199Ôćĺ        }
200Ôćĺ      }
201Ôćĺ    }
202Ôćĺ
203Ôćĺ    // 3-line join
204Ôćĺ    if (i + 2 < nonEmptyLines.length) {
205Ôćĺ      const joined3 = `${line.text} ${nonEmptyLines[i + 1].text} ${nonEmptyLines[i + 2].text}`;
206Ôćĺ      if (passesHardFilters(joined3)) {
207Ôćĺ        const norm = joined3.toLowerCase();
208Ôćĺ        if (!seen.has(norm)) {
209Ôćĺ          seen.add(norm);
210Ôćĺ          candidates.push({ text: joined3, position: line.index });
211Ôćĺ        }
212Ôćĺ      }
213Ôćĺ    }
214Ôćĺ  }
215Ôćĺ
216Ôćĺ  // Pre-filter to 25 before embedding calls: prefer ALL_CAPS and short candidates.
217Ôćĺ  // Position-based scoring handles final ranking.
218Ôćĺ  if (candidates.length > 25) {
219Ôćĺ    const prioritized = candidates.slice().sort((a, b) => {
220Ôćĺ      const aAllCaps = isAllCaps(a.text) ? 0 : 1;
221Ôćĺ      const bAllCaps = isAllCaps(b.text) ? 0 : 1;
222Ôćĺ      if (aAllCaps !== bAllCaps) return aAllCaps - bAllCaps;
223Ôćĺ      const aShort = wordCount(a.text) <= 5 ? 0 : 1;
224Ôćĺ      const bShort = wordCount(b.text) <= 5 ? 0 : 1;
225Ôćĺ      return aShort - bShort;
226Ôćĺ    });
227Ôćĺ    return prioritized.slice(0, 25);
228Ôćĺ  }
229Ôćĺ
230Ôćĺ  return candidates;
231Ôćĺ}
232Ôćĺ
233Ôćĺ// Module-level cache for reference embeddings
234Ôćĺlet cachedTitleRefEmbedding: Array<number> | null = null;
235Ôćĺlet cachedHeaderRefEmbedding: Array<number> | null = null;
236Ôćĺlet cachedNoiseRefEmbedding: Array<number> | null = null;
237Ôćĺ
238Ôćĺexport function _resetEmbeddingCacheForTests(): void {
239Ôćĺ  cachedTitleRefEmbedding = null;
240Ôćĺ  cachedHeaderRefEmbedding = null;
241Ôćĺ  cachedNoiseRefEmbedding = null;
242Ôćĺ}
243Ôćĺ
244Ôćĺexport async function extractTitleWithEmbeddings(
245Ôćĺ  text: string,
246Ôćĺ  embed: EmbedFn
247Ôćĺ): Promise<string | undefined> {
248Ôćĺ  if (!text || text.trim().length === 0) {
249Ôćĺ    return undefined;
250Ôćĺ  }
251Ôćĺ
252Ôćĺ  const lines = text.split("\n");
253Ôćĺ  const candidates = buildCandidates(lines);
254Ôćĺ
255Ôćĺ  if (candidates.length === 0) {
256Ôćĺ    return undefined;
257Ôćĺ  }
258Ôćĺ
259Ôćĺ  // Cache reference embeddings
260Ôćĺ  if (!cachedTitleRefEmbedding) {
261Ôćĺ    cachedTitleRefEmbedding = await embed(TITLE_REFERENCE);
262Ôćĺ  }
263Ôćĺ  if (!cachedHeaderRefEmbedding) {
264Ôćĺ    cachedHeaderRefEmbedding = await embed(HEADER_REFERENCE);
265Ôćĺ  }
266Ôćĺ  if (!cachedNoiseRefEmbedding) {
267Ôćĺ    cachedNoiseRefEmbedding = await embed(NOISE_REFERENCE);
268Ôćĺ  }
269Ôćĺ
270Ôćĺ  // Find the first ALL_CAPS candidate with Ôëą2 words where every significant word has Ôëą4 alpha letters.
271Ôćĺ  // Insignificant tokens (ÔëĄ1 alpha letter: "/", "&", "+", ":", "D)", etc.) are filtered before
272Ôćĺ  // the check so that multi-line joins with continuation punctuation still qualify.
273Ôćĺ  const isStructuralHeading = (c: { text: string }): boolean => {
274Ôćĺ    if (!isAllCaps(c.text) || wordCount(c.text) < 2) return false;
275Ôćĺ    const sigWords = c.text.trim().split(/\s+/).filter((w) => w.replace(/[^A-Z]/g, "").length > 1);
276Ôćĺ    return sigWords.length >= 2 && sigWords.every((w) => w.replace(/[^A-Z]/g, "").length >= 4);
277Ôćĺ  };
278Ôćĺ  const baseHeading = candidates.find(isStructuralHeading);
279Ôćĺ  // When the initial heading has a continuation on the next line introduced by a punctuation token
280Ôćĺ  // (/, &, +, :, or parenthesis), prefer the longer 2-line join as the complete heading.
281Ôćĺ  // E.g. "SAFFRON WHEAT BUNS WITH QUARK" + "/ COTTAGE CHEESE (VARIATION D)" Ôćĺ prefers the join.
282Ôćĺ  // Guard: the remainder after the prefix must start with a continuation character to avoid
283Ôćĺ  // merging two separate consecutive recipe titles (FINNISH MILK FLATBREADS stays separate
284Ôćĺ  // from FINNISH POTATO FLATBREADS because "FINNISH" does not start with a continuation token).
285Ôćĺ  const firstStructuralHeading = baseHeading && (
286Ôćĺ    candidates.find((c) => {
287Ôćĺ      if (!isStructuralHeading(c)) return false;
288Ôćĺ      const hLower = baseHeading.text.toLowerCase();
289Ôćĺ      const cLower = c.text.toLowerCase();
290Ôćĺ      return cLower.startsWith(hLower + " ") && /^[/&+:(]/.test(cLower.slice(hLower.length + 1));
291Ôćĺ    }) ?? baseHeading
292Ôćĺ  );
293Ôćĺ
294Ôćĺ  const scored: Array<{ text: string; position: number; score: number; rawScore: number; baseScore: number }> = [];
295Ôćĺ
296Ôćĺ  for (const candidate of candidates) {
297Ôćĺ    const embedding = await embed(candidate.text);
298Ôćĺ    const titleSim = cosineSimilarity(embedding, cachedTitleRefEmbedding);
299Ôćĺ    const headerSim = cosineSimilarity(embedding, cachedHeaderRefEmbedding);
300Ôćĺ    const noiseSim = cosineSimilarity(embedding, cachedNoiseRefEmbedding);
301Ôćĺ    const rawScore = titleSim - Math.max(headerSim, noiseSim);
302Ôćĺ
303Ôćĺ    // Position factor: multiplicative tiebreaker ÔÇö amplifies existing signal, doesn't replace it
304Ôćĺ    const relativePosition = candidate.position / lines.length;
305Ôćĺ    const positionFactor = relativePosition < 0.5
306Ôćĺ      ? 1.0 + 0.12 * (1 - relativePosition * 2)
307Ôćĺ      : 1.0;
308Ôćĺ
309Ôćĺ    // ALL_CAPS bonus: recipe books use ALL_CAPS for titles and section headings
310Ôćĺ    const allCapsBonus = isAllCaps(candidate.text) && candidate.text.replace(/[^a-zA-Z]/g, "").length >= 4
311Ôćĺ      ? 0.08
312Ôćĺ      : 0;
313Ôćĺ
314Ôćĺ    // Structural heading bonus: first clean ALL_CAPS heading is almost always the recipe title
315Ôćĺ    const structuralBonus =
316Ôćĺ      firstStructuralHeading && candidate === firstStructuralHeading ? 0.10 : 0;
317Ôćĺ
318Ôćĺ    // baseScore excludes position factor ÔÇö used for threshold so position boost on the first
319Ôćĺ    // title doesn't inflate the bar and exclude valid later titles on multi-recipe pages
320Ôćĺ    const baseScore = rawScore + allCapsBonus + structuralBonus;
321Ôćĺ    const score = rawScore * positionFactor + allCapsBonus + structuralBonus;
322Ôćĺ    scored.push({ text: candidate.text, position: candidate.position, score, rawScore, baseScore });
323Ôćĺ  }
324Ôćĺ
325Ôćĺ  if (scored.length === 0) {
326Ôćĺ    return undefined;
327Ôćĺ  }
328Ôćĺ
329Ôćĺ  // Use position-free baseScore for threshold so position boost on the first title doesn't
330Ôćĺ  // inflate the bar and exclude valid later titles on multi-recipe pages.
331Ôćĺ  const bestBaseScore = Math.max(...scored.map((s) => s.baseScore));
332Ôćĺ  const threshold = Math.max(0.08, bestBaseScore * 0.7);
333Ôćĺ
334Ôćĺ  // Filter candidates above threshold
335Ôćĺ  let selected = scored.filter((s) => s.score >= threshold);
336Ôćĺ
337Ôćĺ  // Remove word-boundary prefixes of firstStructuralHeading when the heading itself survived
338Ôćĺ  // the threshold. Cases:
339Ôćĺ  //   ARAYES case:  firstStructuralHeading = "ARAYES SHRAK" (2-word join qualifies; "ARAYES"
340Ôćĺ  //     alone = 1 word, so it never qualified). Filter removes "ARAYES" so dedup keeps the join.
341Ôćĺ  //   SAFFRON case: baseHeading was the partial line; continuation logic above upgraded
342Ôćĺ  //     firstStructuralHeading to the full join. Filter removes the partial so dedup keeps join.
343Ôćĺ  // Safety: only fires when the complete heading itself is in selected (passed the threshold).
344Ôćĺ  if (firstStructuralHeading && selected.some((s) => s.text === firstStructuralHeading.text)) {
345Ôćĺ    const fshLower = firstStructuralHeading.text.toLowerCase();
346Ôćĺ    selected = selected.filter((s) => {
347Ôćĺ      if (s.text === firstStructuralHeading.text) return true;
348Ôćĺ      const sLower = s.text.toLowerCase();
349Ôćĺ      // Remove s if it is a space-delimited prefix of the structural heading
350Ôćĺ      return !fshLower.startsWith(sLower + " ");
351Ôćĺ    });
352Ôćĺ  }
353Ôćĺ
354Ôćĺ  // Deduplicate: if one title is a substring of another, keep the shorter (more focused) one.
355Ôćĺ  // DO NOT CHANGE THIS LOGIC ÔÇö it has been incorrectly "improved" by the title-loop 5 times.
356Ôćĺ  // The tests require shorter wins: "Pierogi Ruskie" over "Pierogi Ruskie 200g m─ůki 3 ziemniaki".
357Ôćĺ  // The pre-filter above handles the conflicting case (structural heading prefix removal) so that
358Ôćĺ  // the incomplete prefix line is never present here when the complete join is in selected.
359Ôćĺ  selected = selected.filter((a) => {
360Ôćĺ    const aLower = a.text.toLowerCase();
361Ôćĺ    return !selected.some(
362Ôćĺ      (b) =>
363Ôćĺ        b !== a &&
364Ôćĺ        aLower.includes(b.text.toLowerCase()) &&
365Ôćĺ        b.text.length < a.text.length
366Ôćĺ    );
367Ôćĺ  });
368Ôćĺ
369Ôćĺ  // Multi-title guard: only join multiple candidates with "+" when there is
370Ôćĺ  // structural evidence of a multi-recipe page (Ôëą2 ALL_CAPS headings).
371Ôćĺ  // A single ALL_CAPS title among mixed-case survivors is a single-recipe page ÔÇö
372Ôćĺ  // collapse to the highest-scoring candidate.
373Ôćĺ  // Zero ALL_CAPS survivors Ôćĺ mixed-case multi-title page Ôćĺ keep all.
374Ôćĺ  if (selected.length > 1) {
375Ôćĺ    const allCapsSelected = selected.filter((s) => isAllCaps(s.text));
376Ôćĺ    if (allCapsSelected.length >= 2) {
377Ôćĺ      selected = allCapsSelected;
378Ôćĺ    } else if (allCapsSelected.length === 1) {
379Ôćĺ      selected = [selected.reduce((a, b) => (a.score > b.score ? a : b))];
380Ôćĺ    }
381Ôćĺ  }
382Ôćĺ
383Ôćĺ  // Cap at 3, sort by document position
384Ôćĺ  selected.sort((a, b) => a.position - b.position);
385Ôćĺ  selected = selected.slice(0, 3);
386Ôćĺ
387Ôćĺ  if (selected.length === 0) {
388Ôćĺ    return undefined;
389Ôćĺ  }
390Ôćĺ
391Ôćĺ  return selected.map((s) => s.text).join(" + ");
392Ôćĺ}
393Ôćĺ
394Ôćĺ/**
395Ôćĺ * Extract potential recipe title from OCR text (sync heuristic fallback)
396Ôćĺ */
397Ôćĺexport function extractTitle(text: string): string | undefined {
398Ôćĺ  if (!text || text.trim().length === 0) {
399Ôćĺ    return undefined;
400Ôćĺ  }
401Ôćĺ
402Ôćĺ  const lines = text.split("\n").map((line) => line.trim());
403Ôćĺ
404Ôćĺ  for (const line of lines) {
405Ôćĺ    if (line.length === 0) continue;
406Ôćĺ    if (line.length < 3 || line.length > 50) continue;
407Ôćĺ    if (looksLikeIngredient(line)) continue;
408Ôćĺ    if (isAllCaps(line)) continue;
409Ôćĺ    if (startsWithNumber(line)) continue;
410Ôćĺ    return line;
411Ôćĺ  }
412Ôćĺ
413Ôćĺ  return undefined;
414Ôćĺ}
415Ôćĺ

